// .npmrc - Security configuration
// Disable arbitrary script execution
ignore-scripts=true
audit=true
audit-level=moderate
engine-strict=true
save-exact=true
package-lock=true
```

```javascript
// app.js - Defensive dependency usage
const express = require('express');
const helmet = require('helmet');

const app = express();
app.use(helmet());

// Validate and sanitize before using parsed data
const validateUserAgent = (uaString) => {
  if (typeof uaString !== 'string' || uaString.length > 500) {
    return null;
  }
  return uaString.replace(/[<>"'&]/g, '');
};

app.get('/user-agent', (req, res) => {
  const ua = validateUserAgent(req.headers['user-agent']);
  if (!ua) {
    return res.status(400).json({ error: 'Invalid user agent' });
  }

  // Use native alternatives where possible
  const basicParsing = {
    browser: ua.includes('Chrome') ? 'Chrome' : 
             ua.includes('Firefox') ? 'Firefox' : 'Other',
    mobile: /Mobile|Android|iPhone/i.test(ua)
  };

  res.json({ parsed: basicParsing });
});

app.listen(3000);
```

**Key Security Controls**:
- **Exact version pinning**: Using exact versions (no `^` or `~`) prevents automatic updates to compromised versions
- **Lockfile enforcement**: package-lock.json ensures reproducible builds with verified checksums
- **ignore-scripts**: Prevents malicious preinstall/postinstall scripts from executing
- **npm audit**: Automatically checks for known vulnerabilities during install

Production applications need continuous monitoring because new vulnerabilities are discovered daily. The Log4Shell vulnerability (CVE-2021-44228) showed how a zero-day in a transitive dependency can affect millions of applications within hours. Here's a comprehensive production setup.

**PRODUCTION PATTERN**:

```javascript
// security/dependency-scanner.js
const { exec } = require('child_process');
const fs = require('fs').promises;
const https = require('https');
const crypto = require('crypto');

class DependencySecurityMonitor {
  constructor(config) {
    this.config = {
      maxSeverity: config.maxSeverity || 'moderate',
      slackWebhook: config.slackWebhook,
      allowedLicenses: config.allowedLicenses || ['MIT', 'Apache-2.0', 'ISC', 'BSD-3-Clause'],
      lockfileHash: null
    };
  }

  async verifyLockfileIntegrity() {
    try {
      const lockfile = await fs.readFile('package-lock.json', 'utf8');
      const currentHash = crypto.createHash('sha256').update(lockfile).digest('hex');

      const storedHash = await fs.readFile('.lockfile-hash', 'utf8').catch(() => null);

      if (storedHash && storedHash.trim() !== currentHash) {
        await this.sendAlert('CRITICAL', 'Lockfile modified unexpectedly', {
          previousHash: storedHash.trim(),
          currentHash: currentHash
        });
        return false;
      }

      await fs.writeFile('.lockfile-hash', currentHash);
      return true;
    } catch (error) {
      console.error('Lockfile verification failed:', error.message);
      return false;
    }
  }

  async runNpmAudit() {
    return new Promise((resolve, reject) => {
      exec('npm audit --json', { maxBuffer: 10 * 1024 * 1024 }, (error, stdout, stderr) => {
        try {
          const result = JSON.parse(stdout);
          resolve(result);
        } catch (parseError) {
          reject(new Error(`Audit parse failed: ${parseError.message}`));
        }
      });
    });
  }

  async checkOSVDatabase(packageName, version) {
    return new Promise((resolve, reject) => {
      const postData = JSON.stringify({
        package: { name: packageName, ecosystem: 'npm' },
        version: version
      });

      const options = {
        hostname: 'api.osv.dev',
        path: '/v1/query',
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(postData)
        },
        timeout: 10000
      };

      const req = https.request(options, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
          try {
            resolve(JSON.parse(data));
          } catch (e) {
            resolve({ vulns: [] });
          }
        });
      });

      req.on('error', reject);
      req.on('timeout', () => reject(new Error('OSV API timeout')));
      req.write(postData);
      req.end();
    });
  }

  async analyzeDependencies() {
    const lockfile = JSON.parse(await fs.readFile('package-lock.json', 'utf8'));
    const dependencies = lockfile.packages || {};
    const issues = [];

    for (const [path, pkg] of Object.entries(dependencies)) {
      if (!path || path === '') continue;

      const packageName = path.replace('node_modules/', '').split('/node_modules/').pop();

      // Check OSV database for vulnerabilities
      try {
        const osvResult = await this.checkOSVDatabase(packageName, pkg.version);
        if (osvResult.vulns && osvResult.vulns.length > 0) {
          issues.push({
            package: packageName,
            version: pkg.version,
            vulnerabilities: osvResult.vulns.map(v => ({
              id: v.id,
              severity: v.severity?.[0]?.score || 'unknown',
              summary: v.summary
            }))
          });
        }
      } catch (error) {
        console.warn(`OSV check failed for ${packageName}: ${error.message}`);
      }
    }

    return issues;
  }

  async sendAlert(severity, message, details) {
    if (!this.config.slackWebhook) return;

    const payload = JSON.stringify({
      text: `🚨 *Dependency Security Alert* [${severity}]`,
      attachments: [{
        color: severity === 'CRITICAL' ? '#ff0000' : '#ffaa00',
        fields: [
          { title: 'Message', value: message, short: false },
          { title: 'Details', value: JSON.stringify(details, null, 2), short: false },
          { title: 'Timestamp', value: new Date().toISOString(), short: true }
        ]
      }]
    });

    const url = new URL(this.config.slackWebhook);
    const options = {
      hostname: url.hostname,
      path: url.pathname,
      method: 'POST',
      headers: { 'Content-Type': 'application/json' }
    };

    return new Promise((resolve) => {
      const req = https.request(options, resolve);
      req.on('error', (e) => console.error('Alert failed:', e.message));
      req.write(payload);
      req.end();
    });
  }

  async fullSecurityScan() {
    console.log('[Security] Starting dependency security scan...');
    const results = { passed: true, issues: [] };

    // Layer 1: Lockfile integrity
    const lockfileValid = await this.verifyLockfileIntegrity();
    if (!lockfileValid) {
      results.passed = false;
      results.issues.push({ type: 'lockfile_tampered', severity: 'CRITICAL' });
    }

    // Layer 2: npm audit
    try {
      const auditResult = await this.runNpmAudit();
      if (auditResult.metadata?.vulnerabilities) {
        const vulns = auditResult.metadata.vulnerabilities;
        if (vulns.critical > 0 || vulns.high > 0) {
          results.passed = false;
          results.issues.push({ 
            type: 'npm_audit', 
            severity: vulns.critical > 0 ? 'CRITICAL' : 'HIGH',
            details: vulns
          });
        }
      }
    } catch (error) {
      console.warn('npm audit failed:', error.message);
    }

    // Layer 3: OSV database check
    const osvIssues = await this.analyzeDependencies();
    if (osvIssues.length > 0) {
      results.issues.push(...osvIssues.map(i => ({ type: 'osv_vuln', ...i })));
    }

    // Send alert if issues found
    if (!results.passed) {
      await this.sendAlert('CRITICAL', 'Dependency vulnerabilities detected', results.issues);
    }

    console.log(`[Security] Scan complete. Passed: ${results.passed}`);
    return results;
  }
}

module.exports = { DependencySecurityMonitor };
```

```yaml
# .github/workflows/dependency-security.yml
name: Dependency Security Scan

on:
  push:
    paths:
      - 'package.json'
      - 'package-lock.json'
  pull_request:
    paths:
      - 'package.json'
      - 'package-lock.json'
  schedule:
    - cron: '0 6 * * *'  # Daily at 6 AM UTC

jobs:
  security-scan:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: '20'
          cache: 'npm'

      - name: Verify lockfile integrity
        run: |
          npm ci --ignore-scripts
          if [ -f .lockfile-hash ]; then
            CURRENT_HASH=$(sha256sum package-lock.json | cut -d' ' -f1)
            STORED_HASH=$(cat .lockfile-hash)
            if [ "$CURRENT_HASH" != "$STORED_HASH" ]; then
              echo "::error::Lockfile hash mismatch!"
              exit 1
            fi
          fi

      - name: Run npm audit
        run: npm audit --audit-level=moderate

      - name: Run Snyk security scan
        uses: snyk/actions/node@master
        env:
          SNYK_TOKEN: ${{ secrets.SNYK_TOKEN }}
        with:
          args: --severity-threshold=high

      - name: Check for known malicious packages
        run: |
          npx socket-security/cli scan
```

```javascript
// scripts/pre-deploy-check.js
const { DependencySecurityMonitor } = require('../security/dependency-scanner');

async function preDeployCheck() {
  const monitor = new DependencySecurityMonitor({
    maxSeverity: 'high',
    slackWebhook: process.env.SLACK_SECURITY_WEBHOOK
  });

  const results = await monitor.fullSecurityScan();

  if (!results.passed) {
    console.error('\n❌ DEPLOYMENT BLOCKED: Security vulnerabilities found\n');
    console.error(JSON.stringify(results.issues, null, 2));
    process.exit(1);
  }

  console.log('\n✅ Security scan passed. Safe to deploy.\n');
  process.exit(0);
}

preDeployCheck().catch((error) => {
  console.error('Security scan failed:', error);
  process.exit(1);
});
```

**Defense in Depth Layers**:

1. **Lockfile Integrity Verification**:
```javascript
// Store and verify SHA-256 hash of package-lock.json
const hash = crypto.createHash('sha256').update(lockfile).digest('hex');
// Detect unauthorized modifications that could introduce malicious packages
```

2. **Multiple Vulnerability Databases**:
```javascript
// Check npm audit, OSV.dev, and Snyk simultaneously
// Different databases have different coverage and detection timing
const npmVulns = await runNpmAudit();
const osvVulns = await checkOSVDatabase(pkg, version);
// Cross-reference for comprehensive coverage
```

3. **CI/CD Gate Enforcement**:
```yaml
# Block deployments with critical/high vulnerabilities
- name: Security gate
  run: npm audit --audit-level=high
  # Pipeline fails if vulnerabilities exceed threshold
```

**Additional Protections**:
- **Dependabot/Renovate**: Automated PR creation for security updates with auto-merge for patch versions
- **Socket.dev**: Detects supply chain attacks, typosquatting, and suspicious package behaviors
- **SBOM Generation**: Create Software Bill of Materials for compliance and incident response
- **Private Registry**: Use Artifactory or Verdaccio to proxy and cache npm packages with security scanning
- **Allowlist Approach**: Only permit pre-approved packages in production applications

Dependency management in Go is critical because vulnerable packages can expose your entire application. The 2023 Terrapin SSH vulnerability (CVE-2023-48795) affected billions of connections because applications used outdated golang.org/x/crypto versions.

**VULNERABLE CODE**:

```go
package main

import (
	"fmt"
	"log"
	"net/http"

	"github.com/dgrijalva/jwt-go" // VULNERABLE: CVE-2020-26160
	"golang.org/x/crypto/ssh"     // VULNERABLE if < v0.17.0: CVE-2023-48795
)

// go.mod with pinned vulnerable versions
// module myservice
// go 1.19
// require (
//     github.com/dgrijalva/jwt-go v3.2.0+incompatible
//     golang.org/x/crypto v0.14.0
// )

func handleAuth(w http.ResponseWriter, r *http.Request) {
	tokenString := r.Header.Get("Authorization")

	// Using deprecated and vulnerable JWT library
	token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
		return []byte("secret-key"), nil
	})

	if err != nil || !token.Valid {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	fmt.Fprintf(w, "Authenticated!")
}

func connectSSH() {
	// Vulnerable SSH configuration
	config := &ssh.ClientConfig{
		User: "admin",
		Auth: []ssh.AuthMethod{
			ssh.Password("password123"),
		},
		HostKeyCallback: ssh.InsecureIgnoreHostKey(), // DANGEROUS
	}

	_, err := ssh.Dial("tcp", "server:22", config)
	if err != nil {
		log.Fatal(err)
	}
}

func main() {
	http.HandleFunc("/auth", handleAuth)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Attack Payload** (JWT Algorithm Confusion):
```text
# CVE-2020-26160: Algorithm confusion attack
# Attacker can forge tokens by changing algorithm to 'none'
eyJhbGciOiJub25lIiwidHlwIjoiSldUIn0.eyJzdWIiOiJhZG1pbiIsImFkbWluIjp0cnVlfQ.
```

**Why This Is Dangerous**:
- `github.com/dgrijalva/jwt-go` is unmaintained and has CVE-2020-26160 (algorithm confusion attack)
- `golang.org/x/crypto` < v0.17.0 is vulnerable to Terrapin SSH attack (CVE-2023-48795)
- No dependency vulnerability scanning in CI/CD pipeline
- Using `InsecureIgnoreHostKey()` disables SSH host verification
- Hardcoded credentials compound the security issues

**SECURE VERSION**:

```go
package main

import (
	"crypto/subtle"
	"fmt"
	"log"
	"net/http"
	"os"
	"time"

	"github.com/golang-jwt/jwt/v5" // SECURE: Maintained fork with security fixes
	"golang.org/x/crypto/ssh"      // SECURE: v0.17.0+ with Terrapin fix
)

// go.mod with secure, updated dependencies
// module myservice
// go 1.21
// require (
//     github.com/golang-jwt/jwt/v5 v5.2.0
//     golang.org/x/crypto v0.18.0
// )

var jwtSecret = []byte(os.Getenv("JWT_SECRET"))

func handleAuth(w http.ResponseWriter, r *http.Request) {
	tokenString := r.Header.Get("Authorization")
	if tokenString == "" {
		http.Error(w, "Missing authorization header", http.StatusUnauthorized)
		return
	}

	// Using maintained jwt library with explicit algorithm validation
	token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
		// CRITICAL: Validate the signing method
		if _, ok := token.Method.(*jwt.SigningMethodHMAC); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}
		return jwtSecret, nil
	}, jwt.WithValidMethods([]string{"HS256"})) // Explicit algorithm whitelist

	if err != nil || !token.Valid {
		log.Printf("Invalid token attempt from %s", r.RemoteAddr)
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	// Validate claims
	if claims, ok := token.Claims.(jwt.MapClaims); ok {
		if exp, ok := claims["exp"].(float64); ok {
			if time.Now().Unix() > int64(exp) {
				http.Error(w, "Token expired", http.StatusUnauthorized)
				return
			}
		}
	}

	fmt.Fprintf(w, "Authenticated!")
}

func connectSSHSecure() (*ssh.Client, error) {
	// Load host key from trusted source
	hostKey, err := loadKnownHostKey("server:22")
	if err != nil {
		return nil, fmt.Errorf("failed to load host key: %w", err)
	}

	// Secure SSH configuration
	config := &ssh.ClientConfig{
		User: os.Getenv("SSH_USER"),
		Auth: []ssh.AuthMethod{
			loadSSHKey(), // Use key-based auth
		},
		HostKeyCallback: ssh.FixedHostKey(hostKey), // Verify host identity
		Timeout:         30 * time.Second,
	}

	return ssh.Dial("tcp", "server:22", config)
}

func loadKnownHostKey(host string) (ssh.PublicKey, error) {
	// Implementation to load from known_hosts file
	return nil, nil
}

func loadSSHKey() ssh.AuthMethod {
	// Implementation to load SSH private key
	return nil
}

func main() {
	if len(jwtSecret) < 32 {
		log.Fatal("JWT_SECRET must be at least 32 bytes")
	}
	http.HandleFunc("/auth", handleAuth)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Key Security Controls**:
- **Updated Dependencies**: Using `github.com/golang-jwt/jwt/v5` (maintained fork) and `golang.org/x/crypto` v0.17.0+ (Terrapin patched)
- **Algorithm Validation**: Explicit whitelist of allowed JWT signing algorithms prevents algorithm confusion attacks
- **Host Key Verification**: Using `ssh.FixedHostKey()` instead of `InsecureIgnoreHostKey()` to prevent MITM attacks
- **Secret Management**: JWT secret loaded from environment variable, not hardcoded

Automated dependency scanning is essential for catching vulnerabilities early. Here's a production-grade approach using multiple layers of defense.

**PRODUCTION PATTERN**:

```go
package main

// dependency_scanner.go - Custom dependency security enforcement
import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/exec"
	"strings"
	"time"
)

// VulnerabilityReport represents a security scan result
type VulnerabilityReport struct {
	Package        string    `json:"package"`
	Version        string    `json:"version"`
	Vulnerability  string    `json:"vulnerability"`
	Severity       string    `json:"severity"`
	FixedVersion   string    `json:"fixed_version"`
	Description    string    `json:"description"`
	DiscoveredAt   time.Time `json:"discovered_at"`
}

// DependencyScanner provides comprehensive vulnerability detection
type DependencyScanner struct {
	govulncheckPath string
	allowedRisk     string // "low", "medium", "high", "critical"
	slackWebhook    string
	blockList       map[string]string // Package -> reason
	logger          *log.Logger
}

// NewDependencyScanner creates a production-ready scanner
func NewDependencyScanner() *DependencyScanner {
	return &DependencyScanner{
		govulncheckPath: "/usr/local/bin/govulncheck",
		allowedRisk:     os.Getenv("MAX_VULN_SEVERITY"), // "low" in prod
		slackWebhook:    os.Getenv("SECURITY_SLACK_WEBHOOK"),
		blockList: map[string]string{
			"github.com/dgrijalva/jwt-go": "Unmaintained, CVE-2020-26160",
			"github.com/unknwon/cae":      "Arbitrary file write CVE-2023-49569",
		},
		logger: log.New(os.Stdout, "[DEP-SCAN] ", log.LstdFlags|log.Lshortfile),
	}
}

// ScanDependencies runs comprehensive vulnerability analysis
func (ds *DependencyScanner) ScanDependencies(ctx context.Context, projectPath string) ([]VulnerabilityReport, error) {
	var vulnerabilities []VulnerabilityReport

	// Layer 1: Check against known blocklist
	blocked, err := ds.checkBlocklist(projectPath)
	if err != nil {
		return nil, fmt.Errorf("blocklist check failed: %w", err)
	}
	vulnerabilities = append(vulnerabilities, blocked...)

	// Layer 2: Run govulncheck for known CVEs
	govulnResults, err := ds.runGovulncheck(ctx, projectPath)
	if err != nil {
		ds.logger.Printf("govulncheck warning: %v", err)
		// Don't fail, continue with other checks
	}
	vulnerabilities = append(vulnerabilities, govulnResults...)

	// Layer 3: Check for outdated dependencies
	outdated, err := ds.checkOutdatedDeps(ctx, projectPath)
	if err != nil {
		ds.logger.Printf("outdated check warning: %v", err)
	}
	vulnerabilities = append(vulnerabilities, outdated...)

	// Layer 4: Verify module integrity
	if err := ds.verifyModuleIntegrity(projectPath); err != nil {
		vulnerabilities = append(vulnerabilities, VulnerabilityReport{
			Package:       "go.sum",
			Severity:      "CRITICAL",
			Description:   fmt.Sprintf("Module integrity check failed: %v", err),
			DiscoveredAt:  time.Now(),
		})
	}

	return vulnerabilities, nil
}

// checkBlocklist verifies no blocklisted packages are in use
func (ds *DependencyScanner) checkBlocklist(projectPath string) ([]VulnerabilityReport, error) {
	var vulns []VulnerabilityReport

	goModPath := projectPath + "/go.mod"
	file, err := os.Open(goModPath)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		line := scanner.Text()
		for pkg, reason := range ds.blockList {
			if strings.Contains(line, pkg) {
				vulns = append(vulns, VulnerabilityReport{
					Package:      pkg,
					Severity:     "CRITICAL",
					Description:  reason,
					DiscoveredAt: time.Now(),
				})
			}
		}
	}

	return vulns, scanner.Err()
}

// runGovulncheck executes official Go vulnerability scanner
func (ds *DependencyScanner) runGovulncheck(ctx context.Context, projectPath string) ([]VulnerabilityReport, error) {
	cmd := exec.CommandContext(ctx, ds.govulncheckPath, "-json", "./...")
	cmd.Dir = projectPath

	output, err := cmd.Output()
	if err != nil {
		// govulncheck exits non-zero when vulns found
		if exitErr, ok := err.(*exec.ExitError); ok {
			output = append(output, exitErr.Stderr...)
		} else {
			return nil, err
		}
	}

	// Parse JSON output and convert to VulnerabilityReport
	return ds.parseGovulncheckOutput(output)
}

// parseGovulncheckOutput converts govulncheck JSON to our format
func (ds *DependencyScanner) parseGovulncheckOutput(output []byte) ([]VulnerabilityReport, error) {
	// Implementation to parse govulncheck JSON format
	return nil, nil
}

// checkOutdatedDeps identifies dependencies with available updates
func (ds *DependencyScanner) checkOutdatedDeps(ctx context.Context, projectPath string) ([]VulnerabilityReport, error) {
	cmd := exec.CommandContext(ctx, "go", "list", "-m", "-u", "-json", "all")
	cmd.Dir = projectPath

	output, err := cmd.Output()
	if err != nil {
		return nil, err
	}

	var vulns []VulnerabilityReport
	decoder := json.NewDecoder(strings.NewReader(string(output)))

	for decoder.More() {
		var mod struct {
			Path    string `json:"Path"`
			Version string `json:"Version"`
			Update  *struct {
				Version string `json:"Version"`
			} `json:"Update"`
		}

		if err := decoder.Decode(&mod); err != nil {
			continue
		}

		if mod.Update != nil {
			vulns = append(vulns, VulnerabilityReport{
				Package:      mod.Path,
				Version:      mod.Version,
				FixedVersion: mod.Update.Version,
				Severity:     "LOW",
				Description:  "Outdated dependency - update available",
				DiscoveredAt: time.Now(),
			})
		}
	}

	return vulns, nil
}

// verifyModuleIntegrity checks go.sum integrity
func (ds *DependencyScanner) verifyModuleIntegrity(projectPath string) error {
	cmd := exec.Command("go", "mod", "verify")
	cmd.Dir = projectPath
	return cmd.Run()
}

// EvaluateRisk determines if build should fail
func (ds *DependencyScanner) EvaluateRisk(vulns []VulnerabilityReport) (bool, string) {
	severityOrder := map[string]int{
		"CRITICAL": 4, "HIGH": 3, "MEDIUM": 2, "LOW": 1,
	}
	allowedLevel := severityOrder[strings.ToUpper(ds.allowedRisk)]

	var criticals, highs int
	for _, v := range vulns {
		if severityOrder[v.Severity] > allowedLevel {
			switch v.Severity {
			case "CRITICAL":
				criticals++
			case "HIGH":
				highs++
			}
		}
	}

	if criticals > 0 {
		return false, fmt.Sprintf("BLOCKED: %d critical vulnerabilities", criticals)
	}
	if highs > 0 {
		return false, fmt.Sprintf("BLOCKED: %d high severity vulnerabilities", highs)
	}
	return true, "PASSED: No blocking vulnerabilities found"
}

// AlertSecurityTeam sends notifications for critical findings
func (ds *DependencyScanner) AlertSecurityTeam(vulns []VulnerabilityReport) error {
	if ds.slackWebhook == "" {
		return nil
	}

	for _, v := range vulns {
		if v.Severity == "CRITICAL" || v.Severity == "HIGH" {
			msg := fmt.Sprintf(
				":warning: *Security Alert* - %s vulnerability in `%s@%s`\n"+
					"CVE: %s\nFix: Upgrade to %s\n%s",
				v.Severity, v.Package, v.Version,
				v.Vulnerability, v.FixedVersion, v.Description,
			)
			ds.sendSlackMessage(msg)
		}
	}
	return nil
}

func (ds *DependencyScanner) sendSlackMessage(msg string) {
	payload := fmt.Sprintf(`{"text": %q}`, msg)
	http.Post(ds.slackWebhook, "application/json", strings.NewReader(payload))
}

func main() {
	scanner := NewDependencyScanner()
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Minute)
	defer cancel()

	vulns, err := scanner.ScanDependencies(ctx, ".")
	if err != nil {
		log.Fatalf("Scan failed: %v", err)
	}

	// Alert on findings
	scanner.AlertSecurityTeam(vulns)

	// Evaluate and exit with appropriate code for CI/CD
	passed, message := scanner.EvaluateRisk(vulns)
	fmt.Println(message)

	if !passed {
		os.Exit(1) // Fail the build
	}
}
