```php
<?php
// src/Security/DependencySecurityChecker.php
namespace App\Security;

use Psr\Log\LoggerInterface;
use Symfony\Component\Process\Process;
use Symfony\Component\Process\Exception\ProcessFailedException;

class DependencySecurityChecker
{
    private LoggerInterface $logger;
    private string $projectRoot;
    private array $allowedVulnerabilities;

    public function __construct(
        LoggerInterface $logger,
        string $projectRoot,
        array $allowedVulnerabilities = []
    ) {
        $this->logger = $logger;
        $this->projectRoot = $projectRoot;
        $this->allowedVulnerabilities = $allowedVulnerabilities;
    }

    public function runAudit(): array
    {
        $process = new Process(
            ['composer', 'audit', '--format=json'],
            $this->projectRoot
        );

        $process->run();

        $output = $process->getOutput();
        $results = json_decode($output, true) ?? [];

        return $this->processResults($results);
    }

    private function processResults(array $results): array
    {
        $criticalFindings = [];
        $allowedFindings = [];
        $advisories = $results['advisories'] ?? [];

        foreach ($advisories as $packageName => $packageAdvisories) {
            foreach ($packageAdvisories as $advisory) {
                $advisoryId = $advisory['advisoryId'] ?? $advisory['cve'] ?? 'unknown';

                if ($this->isAllowed($advisoryId)) {
                    $allowedFindings[] = [
                        'package' => $packageName,
                        'advisory' => $advisoryId,
                        'reason' => $this->getAllowedReason($advisoryId),
                    ];
                    continue;
                }

                $criticalFindings[] = [
                    'package' => $packageName,
                    'title' => $advisory['title'] ?? 'Unknown',
                    'cve' => $advisory['cve'] ?? 'N/A',
                    'severity' => $advisory['severity'] ?? 'unknown',
                    'affectedVersions' => $advisory['affectedVersions'] ?? 'unknown',
                    'link' => $advisory['link'] ?? '',
                ];
            }
        }

        $this->logFindings($criticalFindings, $allowedFindings);

        return [
            'critical' => $criticalFindings,
            'allowed' => $allowedFindings,
            'hasBlockingIssues' => count($criticalFindings) > 0,
        ];
    }

    private function isAllowed(string $advisoryId): bool
    {
        return isset($this->allowedVulnerabilities[$advisoryId]);
    }

    private function getAllowedReason(string $advisoryId): string
    {
        return $this->allowedVulnerabilities[$advisoryId]['reason'] ?? 'No reason provided';
    }

    private function logFindings(array $critical, array $allowed): void
    {
        foreach ($critical as $finding) {
            $this->logger->error('Critical vulnerability detected', [
                'package' => $finding['package'],
                'cve' => $finding['cve'],
                'severity' => $finding['severity'],
            ]);
        }

        foreach ($allowed as $finding) {
            $this->logger->warning('Allowed vulnerability (with compensating controls)', [
                'package' => $finding['package'],
                'advisory' => $finding['advisory'],
                'reason' => $finding['reason'],
            ]);
        }
    }
}
