<?php
// src/Middleware/VulnerabilityMitigationMiddleware.php
namespace App\Http\Middleware;

use Closure;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Log;

class VulnerabilityMitigationMiddleware
{
    /**
     * Compensating controls for known but unpatched vulnerabilities
     */
    private array $mitigations = [
        // Block patterns associated with CVE-2021-3129 (Ignition RCE)
        '/_ignition/execute-solution' => 'block',
        '/_ignition/health-check' => 'block',
    ];

    public function handle(Request $request, Closure $next)
    {
        $path = $request->getPathInfo();

        // Check for known exploit paths
        foreach ($this->mitigations as $pattern => $action) {
            if (str_contains($path, $pattern)) {
                Log::warning('Blocked potential exploit attempt', [
                    'path' => $path,
                    'ip' => $request->ip(),
                    'user_agent' => $request->userAgent(),
                    'pattern_matched' => $pattern,
                ]);

                abort(404); // Don't reveal existence
            }
        }

        // Check for file inclusion/path traversal patterns
        $suspiciousPatterns = [
            'php://filter',
            'phar://',
            'expect://',
            '../',
            '..\\',
        ];

        $requestContent = $request->getContent();
        foreach ($suspiciousPatterns as $pattern) {
            if (str_contains($requestContent, $pattern)) {
                Log::critical('Potential RCE attempt blocked', [
                    'ip' => $request->ip(),
                    'pattern' => $pattern,
                    'path' => $path,
                ]);
                abort(400, 'Invalid request');
            }
        }

        return $next($request);
    }
}
