<?php
// src/Console/Commands/SecurityAuditCommand.php
namespace App\Console\Commands;

use App\Security\DependencySecurityChecker;
use Illuminate\Console\Command;
use Illuminate\Support\Facades\Notification;
use App\Notifications\SecurityAlertNotification;

class SecurityAuditCommand extends Command
{
    protected $signature = 'security:audit {--fail-on-critical}';
    protected $description = 'Run dependency security audit';

    public function handle(DependencySecurityChecker $checker): int
    {
        $this->info('Running security audit...');

        $results = $checker->runAudit();

        if (count($results['critical']) > 0) {
            $this->error('Critical vulnerabilities found:');

            foreach ($results['critical'] as $vuln) {
                $this->line(sprintf(
                    '  [%s] %s: %s (%s)',
                    $vuln['severity'],
                    $vuln['package'],
                    $vuln['title'],
                    $vuln['cve']
                ));
            }

            // Send alert to security team
            Notification::route('slack', config('services.slack.security_webhook'))
                ->notify(new SecurityAlertNotification($results['critical']));

            if ($this->option('fail-on-critical')) {
                return Command::FAILURE;
            }
        }

        if (count($results['allowed']) > 0) {
            $this->warn('Allowed vulnerabilities (with mitigations):');
            foreach ($results['allowed'] as $allowed) {
                $this->line(sprintf(
                    '  %s: %s (Reason: %s)',
                    $allowed['package'],
                    $allowed['advisory'],
                    $allowed['reason']
                ));
            }
        }

        $this->info('Audit complete.');
        return Command::SUCCESS;
    }
}
