```javascript
// app.js - Secure usage with input validation
const express = require('express');
const { merge } = require('lodash');
const { format, parseISO, isValid } = require('date-fns');

const app = express();
app.use(express.json({ limit: '10kb' }));

// Prototype pollution prevention middleware
function sanitizeObject(obj, depth = 0, maxDepth = 10) {
  if (depth > maxDepth || obj === null || typeof obj !== 'object') {
    return obj;
  }

  const sanitized = Array.isArray(obj) ? [] : {};

  for (const key of Object.keys(obj)) {
    // Block prototype pollution attempts
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      console.warn(`Blocked prototype pollution attempt: ${key}`);
      continue;
    }
    sanitized[key] = sanitizeObject(obj[key], depth + 1, maxDepth);
  }

  return sanitized;
}

app.post('/api/merge', (req, res) => {
  try {
    const sanitizedTarget = sanitizeObject(req.body.target);
    const sanitizedSource = sanitizeObject(req.body.source);

    // Safe merge with sanitized inputs
    const result = merge({}, sanitizedTarget, sanitizedSource);
    res.json(result);
  } catch (error) {
    console.error('Merge error:', error.message);
    res.status(400).json({ error: 'Invalid input' });
  }
});

app.get('/api/time', (req, res) => {
  const dateInput = req.query.date;

  // Validate date format to prevent ReDoS
  if (!dateInput || !/^\d{4}-\d{2}-\d{2}$/.test(dateInput)) {
    return res.status(400).json({ error: 'Invalid date format. Use YYYY-MM-DD' });
  }

  const parsed = parseISO(dateInput);
  if (!isValid(parsed)) {
    return res.status(400).json({ error: 'Invalid date' });
  }

  res.json({ time: format(parsed, 'yyyy-MM-dd') });
});

app.listen(3000);
```

**Key Security Controls**:
- **Pinned versions**: Exact version numbers prevent auto-upgrade to compromised releases
- **npm audit**: Built-in vulnerability scanner runs on every install
- **Resolutions**: Override vulnerable transitive dependencies
- **Input sanitization**: Block prototype pollution at application level
- **Replaced moment.js**: Using date-fns which has better security track record

