// scripts/security-monitor.js - Custom monitoring script
const https = require('https');
const fs = require('fs');
const { execSync } = require('child_process');

class DependencySecurityMonitor {
  constructor(options = {}) {
    this.slackWebhook = process.env.SLACK_SECURITY_WEBHOOK;
    this.pagerDutyKey = process.env.PAGERDUTY_ROUTING_KEY;
    this.severityThreshold = options.severityThreshold || 'moderate';
    this.allowedAdvisories = new Set(options.allowedAdvisories || []);
  }

  async runAudit() {
    const timestamp = new Date().toISOString();
    console.log(`[${timestamp}] Starting security audit...`);

    try {
      // Run npm audit and capture output
      const auditOutput = execSync('npm audit --json', {
        encoding: 'utf8',
        maxBuffer: 10 * 1024 * 1024
      });

      return JSON.parse(auditOutput);
    } catch (error) {
      // npm audit exits with non-zero when vulnerabilities found
      if (error.stdout) {
        return JSON.parse(error.stdout);
      }
      throw error;
    }
  }

  categorizeVulnerabilities(auditResult) {
    const vulnerabilities = auditResult.vulnerabilities || {};
    const categorized = {
      critical: [],
      high: [],
      moderate: [],
      low: [],
      info: []
    };

    for (const [pkgName, vuln] of Object.entries(vulnerabilities)) {
      const severity = vuln.severity?.toLowerCase() || 'info';

      // Skip allowed advisories (after security review)
      if (vuln.via?.some(v => this.allowedAdvisories.has(v.source))) {
        continue;
      }

      categorized[severity].push({
        package: pkgName,
        severity: vuln.severity,
        range: vuln.range,
        fixAvailable: vuln.fixAvailable,
        via: vuln.via
      });
    }

    return categorized;
  }

  async sendSlackAlert(vulnerabilities) {
    if (!this.slackWebhook) return;

    const message = {
      text: ':warning: Security Alert: Vulnerable Dependencies Detected',
      blocks: [
        {
          type: 'header',
          text: {
            type: 'plain_text',
            text: '🚨 Dependency Security Alert'
          }
        },
        {
          type: 'section',
          fields: [
            {
              type: 'mrkdwn',
              text: `*Critical:* ${vulnerabilities.critical.length}`
            },
            {
              type: 'mrkdwn',
              text: `*High:* ${vulnerabilities.high.length}`
            },
            {
              type: 'mrkdwn',
              text: `*Moderate:* ${vulnerabilities.moderate.length}`
            },
            {
              type: 'mrkdwn',
              text: `*Low:* ${vulnerabilities.low.length}`
            }
          ]
        }
      ]
    };

    // Add critical vulnerabilities detail
    if (vulnerabilities.critical.length > 0) {
      message.blocks.push({
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: '*Critical Vulnerabilities:*\n' + 
            vulnerabilities.critical
              .slice(0, 5)
              .map(v => `• \`${v.package}\` (${v.range})`)
              .join('\n')
        }
      });
    }

    await this.httpPost(this.slackWebhook, message);
  }

  async triggerPagerDuty(vulnerabilities) {
    if (!this.pagerDutyKey || vulnerabilities.critical.length === 0) return;

    const event = {
      routing_key: this.pagerDutyKey,
      event_action: 'trigger',
      payload: {
        summary: `CRITICAL: ${vulnerabilities.critical.length} critical vulnerabilities detected`,
        severity: 'critical',
        source: 'dependency-security-monitor',
        custom_details: {
          critical_packages: vulnerabilities.critical.map(v => v.package),
          total_vulnerabilities: {
            critical: vulnerabilities.critical.length,
            high: vulnerabilities.high.length,
            moderate: vulnerabilities.moderate.length
          }
        }
      }
    };

    await this.httpPost(
      'https://events.pagerduty.com/v2/enqueue',
      event
    );
  }

  httpPost(url, data) {
    return new Promise((resolve, reject) => {
      const urlObj = new URL(url);
      const postData = JSON.stringify(data);

      const req = https.request({
        hostname: urlObj.hostname,
        port: 443,
        path: urlObj.pathname,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(postData)
        }
      }, (res) => {
        resolve(res.statusCode);
      });

      req.on('error', reject);
      req.write(postData);
      req.end();
    });
  }

  async monitor() {
    try {
      const auditResult = await this.runAudit();
      const vulnerabilities = this.categorizeVulnerabilities(auditResult);

      console.log('Vulnerability Summary:');
      console.log(`  Critical: ${vulnerabilities.critical.length}`);
      console.log(`  High: ${vulnerabilities.high.length}`);
      console.log(`  Moderate: ${vulnerabilities.moderate.length}`);
      console.log(`  Low: ${vulnerabilities.low.length}`);

      // Alert based on severity
      if (vulnerabilities.critical.length > 0) {
        await this.triggerPagerDuty(vulnerabilities);
        await this.sendSlackAlert(vulnerabilities);
        process.exit(1);
      } else if (vulnerabilities.high.length > 0) {
        await this.sendSlackAlert(vulnerabilities);
        process.exit(1);
      }

      console.log('Security audit passed!');
      process.exit(0);
    } catch (error) {
      console.error('Security monitor failed:', error.message);
      process.exit(2);
    }
  }
}

// Run monitor
const monitor = new DependencySecurityMonitor({
  severityThreshold: 'moderate',
  allowedAdvisories: [
    // Example: Advisory reviewed and accepted risk
    // 1089153 - prototype pollution in xyz, mitigated by input validation
  ]
});

monitor.monitor();
