// DependencySecurityConfig.java - Runtime security controls
package com.enterprise.security;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.boot.actuate.health.HealthIndicator;
import org.springframework.boot.actuate.health.Health;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.annotation.PostConstruct;
import java.io.InputStream;
import java.util.Properties;
import java.util.Set;

@Configuration
public class DependencySecurityConfig {

    private static final Logger securityLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Known vulnerable package prefixes to detect at runtime
    private static final Set<String> SUSPICIOUS_PACKAGES = Set.of(
        "org.apache.log4j",  // Old Log4j 1.x
        "com.thoughtworks.xstream",  // Often vulnerable
        "org.apache.commons.collections"  // Deserialization gadgets
    );

    @PostConstruct
    public void validateDependencies() {
        // Runtime verification of critical dependencies
        verifyLog4jVersion();
        verifyJacksonVersion();
        detectSuspiciousClasses();

        securityLog.info("Dependency security validation completed");
    }

    private void verifyLog4jVersion() {
        try {
            Class<?> log4jClass = Class.forName(
                "org.apache.logging.log4j.core.LoggerContext"
            );
            Package pkg = log4jClass.getPackage();
            String version = pkg.getImplementationVersion();

            if (version != null && isVulnerableLog4jVersion(version)) {
                securityLog.error(
                    "CRITICAL: Vulnerable Log4j version detected: {}", 
                    version
                );
                throw new SecurityException(
                    "Application startup blocked: vulnerable Log4j " + version
                );
            }
        } catch (ClassNotFoundException e) {
            // Log4j not present - acceptable
            securityLog.debug("Log4j core not in classpath");
        }
    }

    private boolean isVulnerableLog4jVersion(String version) {
        // Log4j < 2.17.0 is vulnerable to various CVEs
        String[] parts = version.split("\\.");
        if (parts.length >= 2) {
            int major = Integer.parseInt(parts[0]);
            int minor = Integer.parseInt(parts[1]);
            return major == 2 && minor < 17;
        }
        return true; // Assume vulnerable if can't parse
    }

    private void verifyJacksonVersion() {
        try {
            Properties props = new Properties();
            InputStream is = getClass().getResourceAsStream(
                "/META-INF/maven/com.fasterxml.jackson.core/" +
                "jackson-databind/pom.properties"
            );
            if (is != null) {
                props.load(is);
                String version = props.getProperty("version");
                securityLog.info("Jackson-databind version: {}", version);
            }
        } catch (Exception e) {
            securityLog.warn("Could not verify Jackson version", e);
        }
    }

    private void detectSuspiciousClasses() {
        // Check for known gadget chain classes
        String[] gadgetClasses = {
            "org.apache.commons.collections.functors.InvokerTransformer",
            "org.apache.xalan.xsltc.trax.TemplatesImpl",
            "com.sun.org.apache.xalan.internal.xsltc.trax.TemplatesImpl"
        };

        for (String className : gadgetClasses) {
            try {
                Class.forName(className);
                securityLog.warn(
                    "SECURITY: Potential deserialization gadget detected: {}",
                    className
                );
            } catch (ClassNotFoundException e) {
                // Expected - class not present
            }
        }
    }

    @Bean
    public HealthIndicator dependencySecurityHealth() {
        return () -> {
            try {
                verifyLog4jVersion();
                return Health.up()
                    .withDetail("log4j", "secure")
                    .withDetail("lastCheck", System.currentTimeMillis())
                    .build();
            } catch (SecurityException e) {
                return Health.down()
                    .withDetail("vulnerability", e.getMessage())
                    .build();
            }
        };
    }
}
