Dependency management in Go is critical for security. Many Go applications use outdated or vulnerable packages without realizing it. The 2023 go-resty vulnerability (CVE-2023-45286) affected thousands of applications due to a race condition that leaked HTTP request bodies between concurrent requests.

**VULNERABLE CODE**:

```go
package main

import (
	"fmt"
	"log"

	"github.com/go-resty/resty/v2" // v2.7.0 - VULNERABLE VERSION
)

var client = resty.New() // Shared client without proper configuration

func makeAPIRequest(userToken string, payload []byte) (string, error) {
	// VULNERABLE: Using vulnerable version of go-resty
	// Race condition can leak request bodies between concurrent requests
	resp, err := client.R().
		SetHeader("Authorization", "Bearer "+userToken).
		SetBody(payload).
		Post("https://api.example.com/data")

	if err != nil {
		return "", err
	}

	return resp.String(), nil
}

func main() {
	// Concurrent requests from different users
	go func() {
		result, _ := makeAPIRequest("user1-secret-token", []byte(`{"credit_card": "4111-1111-1111-1111"}`))
		fmt.Println("User1:", result)
	}()

	go func() {
		result, _ := makeAPIRequest("user2-token", []byte(`{"name": "John"}`))
		fmt.Println("User2:", result)
	}()

	select {} // Keep alive
}
```

**go.mod (VULNERABLE)**:
```text
module myapp

go 1.21

require github.com/go-resty/resty/v2 v2.7.0
```

**Attack Vector**:
```bash
# Attacker sends many concurrent requests to trigger race condition
for i in {1..1000}; do
  curl -X POST https://target.com/api/endpoint \
    -H "Authorization: Bearer attacker_token" \
    -d '{"probe": "test"}' &
done
# Due to race condition, attacker may receive other users' request bodies
```

**Why This Is Dangerous**:
- Vulnerable go-resty v2.7.0 has race condition in request body handling
- Concurrent requests can cause data leakage between users
- Sensitive data like auth tokens, credit cards, PII can be exposed
- No dependency scanning or version pinning in place

**SECURE VERSION**:

```go
package main

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"time"

	"github.com/go-resty/resty/v2" // v2.11.0+ - PATCHED VERSION
)

// SecureHTTPClient wraps resty with security best practices
type SecureHTTPClient struct {
	client *resty.Client
}

func NewSecureHTTPClient() *SecureHTTPClient {
	client := resty.New().
		SetTimeout(30 * time.Second).
		SetRetryCount(3).
		SetRetryWaitTime(1 * time.Second).
		SetTLSClientConfig(&tls.Config{
			MinVersion: tls.VersionTLS12,
		}).
		OnBeforeRequest(func(c *resty.Client, r *resty.Request) error {
			// Add request ID for tracing
			r.SetHeader("X-Request-ID", generateRequestID())
			return nil
		}).
		OnAfterResponse(func(c *resty.Client, r *resty.Response) error {
			// Log response for security monitoring
			log.Printf("[HTTP] %s %s -> %d", r.Request.Method, r.Request.URL, r.StatusCode())
			return nil
		})

	return &SecureHTTPClient{client: client}
}

func (s *SecureHTTPClient) MakeAPIRequest(ctx context.Context, userToken string, payload []byte) (string, error) {
	// Create new request with context for proper cancellation
	resp, err := s.client.R().
		SetContext(ctx).
		SetHeader("Authorization", "Bearer "+userToken).
		SetHeader("Content-Type", "application/json").
		SetBody(payload).
		Post("https://api.example.com/data")

	if err != nil {
		log.Printf("[ERROR] API request failed: %v", err)
		return "", fmt.Errorf("request failed: %w", err)
	}

	if resp.StatusCode() >= 400 {
		return "", fmt.Errorf("API error: status %d", resp.StatusCode())
	}

	return resp.String(), nil
}
