	lastScanTime      time.Time
	scanInterval      time.Duration
	alertCallback     func([]DependencyVulnerability)
	allowedVulnIDs    map[string]bool // Explicitly acknowledged vulns
	blockOnCritical   bool
}

// NewDependencyScanner creates a configured scanner
func NewDependencyScanner(config ScannerConfig) *DependencyScanner {
	scanner := &DependencyScanner{
		scanInterval:    config.ScanInterval,
		alertCallback:   config.AlertCallback,
		allowedVulnIDs:  make(map[string]bool),
		blockOnCritical: config.BlockOnCritical,
	}

	// Load acknowledged vulnerabilities from config
	for _, vulnID := range config.AcknowledgedVulns {
		scanner.allowedVulnIDs[vulnID] = true
	}

	return scanner
}

type ScannerConfig struct {
	ScanInterval       time.Duration
	AlertCallback      func([]DependencyVulnerability)
	AcknowledgedVulns  []string
	BlockOnCritical    bool
}

// RunGovulncheck executes govulncheck and parses results
func (ds *DependencyScanner) RunGovulncheck(ctx context.Context, projectPath string) ([]DependencyVulnerability, error) {
	log.Printf("[SECURITY] Starting vulnerability scan for: %s", projectPath)

	// Run govulncheck (Go's official vulnerability scanner)
	cmd := exec.CommandContext(ctx, "govulncheck", "-json", "./...")
	cmd.Dir = projectPath

	output, err := cmd.Output()
	if err != nil {
		// govulncheck returns non-zero if vulnerabilities found
		if exitErr, ok := err.(*exec.ExitError); ok {
			log.Printf("[SECURITY] govulncheck found issues, parsing results")
			output = append(output, exitErr.Stderr...)
		} else {
			return nil, fmt.Errorf("govulncheck execution failed: %w", err)
		}
	}

	vulns, err := ds.parseGovulncheckOutput(output)
	if err != nil {
		return nil, fmt.Errorf("failed to parse govulncheck output: %w", err)
	}

	ds.mu.Lock()
	ds.vulnerabilities = vulns
	ds.lastScanTime = time.Now()
	ds.mu.Unlock()

	// Filter out acknowledged vulnerabilities for alerting
	unacknowledged := ds.filterUnacknowledged(vulns)

	if len(unacknowledged) > 0 {
		log.Printf("[SECURITY] Found %d unacknowledged vulnerabilities", len(unacknowledged))
		if ds.alertCallback != nil {
			ds.alertCallback(unacknowledged)
		}

		// Block deployment if critical vulnerabilities found
		if ds.blockOnCritical && ds.hasCriticalVulns(unacknowledged) {
			return unacknowledged, fmt.Errorf("CRITICAL vulnerabilities detected, blocking deployment")
		}
	}

	return vulns, nil
}

func (ds *DependencyScanner) filterUnacknowledged(vulns []DependencyVulnerability) []DependencyVulnerability {
	var result []DependencyVulnerability
	for _, v := range vulns {
		if !ds.allowedVulnIDs[v.CVE] {
			result = append(result, v)
		}
	}
	return result
}

func (ds *DependencyScanner) hasCriticalVulns(vulns []DependencyVulnerability) bool {
	for _, v := range vulns {
		if strings.ToUpper(v.Severity) == "CRITICAL" || strings.ToUpper(v.Severity) == "HIGH" {
			return true
		}
	}
	return false
}

// StartPeriodicScan runs vulnerability scans on a schedule
func (ds *DependencyScanner) StartPeriodicScan(ctx context.Context, projectPath string) {
	ticker := time.NewTicker(ds.scanInterval)
	defer ticker.Stop()

	// Initial scan
	ds.RunGovulncheck(ctx, projectPath)

	for {
		select {
		case <-ctx.Done():
			log.Println("[SECURITY] Stopping periodic vulnerability scan")
			return
		case <-ticker.C:
			if _, err := ds.RunGovulncheck(ctx, projectPath); err != nil {
				log.Printf("[SECURITY] Scan error: %v", err)
			}
		}
	}
}

// GetVulnerabilityReport returns current vulnerability status
func (ds *DependencyScanner) GetVulnerabilityReport() VulnerabilityReport {
	ds.mu.RLock()
	defer ds.mu.RUnlock()

	return VulnerabilityReport{
		LastScan:        ds.lastScanTime,
		Vulnerabilities: ds.vulnerabilities,
		TotalCount:      len(ds.vulnerabilities),
		CriticalCount:   ds.countBySeverity("CRITICAL"),
		HighCount:       ds.countBySeverity("HIGH"),
		MediumCount:     ds.countBySeverity("MEDIUM"),
		LowCount:        ds.countBySeverity("LOW"),
	}
}

type VulnerabilityReport struct {
	LastScan        time.Time                 `json:"last_scan"`
	Vulnerabilities []DependencyVulnerability `json:"vulnerabilities"`
	TotalCount      int                       `json:"total_count"`
	CriticalCount   int                       `json:"critical_count"`
	HighCount       int                       `json:"high_count"`
	MediumCount     int                       `json:"medium_count"`
	LowCount        int                       `json:"low_count"`
}
