require 'vendor/autoload.php';

use PHPMailer\PHPMailer\PHPMailer;
use PHPMailer\PHPMailer\SMTP;
use PHPMailer\PHPMailer\Exception;
use GuzzleHttp\Client;
use Monolog\Logger;
use Monolog\Handler\StreamHandler;

class SecureContactHandler
{
    private PHPMailer $mail;
    private Logger $logger;

    public function __construct()
    {
        $this->logger = new Logger('contact');
        $this->logger->pushHandler(new StreamHandler('/var/log/app/contact.log', Logger::INFO));

        $this->mail = new PHPMailer(true);
        $this->mail->isSMTP();
        $this->mail->SMTPAuth = true;
        $this->mail->Host = getenv('SMTP_HOST');
        $this->mail->Username = getenv('SMTP_USER');
        $this->mail->Password = getenv('SMTP_PASS');
        $this->mail->SMTPSecure = PHPMailer::ENCRYPTION_STARTTLS;
    }

    public function sendContact(string $email, string $subject, string $message): bool
    {
        // Validate email strictly
        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            $this->logger->warning('Invalid email rejected', ['email' => substr($email, 0, 50)]);
            throw new InvalidArgumentException('Invalid email format');
        }

        // Sanitize subject and message
        $subject = mb_substr(strip_tags($subject), 0, 100);
        $message = htmlspecialchars($message, ENT_QUOTES, 'UTF-8');

        try {
            $this->mail->setFrom('noreply@example.com', 'Contact Form');
            $this->mail->addReplyTo($email);
            $this->mail->addAddress('admin@example.com');
            $this->mail->Subject = $subject;
            $this->mail->Body = $message;
            $this->mail->send();

            $this->logger->info('Contact email sent', ['replyTo' => $email]);
            return true;
        } catch (Exception $e) {
            $this->logger->error('Email failed', ['error' => $e->getMessage()]);
            throw new RuntimeException('Failed to send email');
        }
    }
}
```

**Key Security Controls**:
- **roave/security-advisories**: Prevents installing packages with known vulnerabilities via Composer conflict rules
- **Caret version constraints (^)**: Allow minor/patch updates for security fixes while preventing breaking changes
- **composer.lock committed**: Ensures all environments use identical, tested dependency versions
- **Input validation**: Email validated before use, not passed directly to mail functions

Supply chain attacks have become increasingly sophisticated. The 2024 polyfill.io compromise affected 100,000+ websites when the CDN domain was sold and began serving malicious code. In PHP specifically, the 2021 Composer supply chain attack targeted php.net's git server. Here's a comprehensive defense strategy:

