<?php
// src/Security/DependencySecurityMonitor.php

declare(strict_types=1);

namespace App\Security;

use Psr\Log\LoggerInterface;
use Symfony\Contracts\HttpClient\HttpClientInterface;

class DependencySecurityMonitor
{
    private const PACKAGIST_API = 'https://packagist.org/packages/';
    private const SECURITY_ADVISORIES_API = 'https://packagist.org/api/security-advisories/';

    public function __construct(
        private readonly HttpClientInterface $httpClient,
        private readonly LoggerInterface $logger,
        private readonly string $projectRoot
    ) {}

    /**
     * Validates composer.lock integrity using hash verification
     */
    public function verifyLockFileIntegrity(): bool
    {
        $lockFile = $this->projectRoot . '/composer.lock';
        $storedHash = $this->projectRoot . '/.composer.lock.sha256';

        if (!file_exists($lockFile)) {
            throw new \RuntimeException('composer.lock not found - dependency pinning required');
        }

        $currentHash = hash_file('sha256', $lockFile);

        if (file_exists($storedHash)) {
            $expectedHash = trim(file_get_contents($storedHash));
            if (!hash_equals($expectedHash, $currentHash)) {
                $this->logger->critical('composer.lock hash mismatch - possible tampering', [
                    'expected' => substr($expectedHash, 0, 16) . '...',
                    'actual' => substr($currentHash, 0, 16) . '...',
                ]);
                return false;
            }
        }

        return true;
    }

    /**
     * Scans installed packages against security advisories
     */
    public function scanForVulnerabilities(): array
    {
        $lockFile = $this->projectRoot . '/composer.lock';
        $lock = json_decode(file_get_contents($lockFile), true);

        $packages = [];
        foreach ($lock['packages'] ?? [] as $package) {
            $packages[$package['name']] = $package['version'];
        }

        $response = $this->httpClient->request('POST', self::SECURITY_ADVISORIES_API, [
            'json' => ['packages' => $packages],
            'timeout' => 30,
        ]);

        $advisories = $response->toArray();
        $vulnerabilities = [];

        foreach ($advisories['advisories'] ?? [] as $packageName => $packageAdvisories) {
            foreach ($packageAdvisories as $advisory) {
                $vulnerabilities[] = [
                    'package' => $packageName,
                    'installed_version' => $packages[$packageName] ?? 'unknown',
                    'advisory_id' => $advisory['advisoryId'] ?? 'N/A',
                    'cve' => $advisory['cve'] ?? 'N/A',
                    'title' => $advisory['title'] ?? 'Unknown vulnerability',
                    'severity' => $this->determineSeverity($advisory),
                    'affected_versions' => $advisory['affectedVersions'] ?? 'unknown',
                    'link' => $advisory['link'] ?? null,
                ];

                $this->logger->alert('Vulnerable dependency detected', [
                    'package' => $packageName,
                    'cve' => $advisory['cve'] ?? 'N/A',
                ]);
            }
        }

        return $vulnerabilities;
    }

    /**
     * Checks package provenance and maintainer reputation
     */
    public function validatePackageProvenance(string $packageName): array
    {
        $response = $this->httpClient->request('GET', self::PACKAGIST_API . $packageName . '.json');
        $data = $response->toArray();
        $package = $data['package'] ?? [];

        $risks = [];

        // Check download count (low = potential typosquatting)
        $downloads = $package['downloads']['total'] ?? 0;
        if ($downloads < 10000) {
            $risks[] = [
                'type' => 'low_adoption',
                'severity' => 'medium',
                'message' => "Package has only {$downloads} downloads - verify legitimacy",
            ];
        }

        // Check if abandoned
        if (!empty($package['abandoned'])) {
            $risks[] = [
                'type' => 'abandoned',
                'severity' => 'high',
                'message' => 'Package is abandoned: ' . ($package['abandoned'] === true ? 'no replacement' : $package['abandoned']),
            ];
        }

        // Check last update date
        $lastUpdate = $package['time'] ?? null;
        if ($lastUpdate) {
            $daysSinceUpdate = (time() - strtotime($lastUpdate)) / 86400;
            if ($daysSinceUpdate > 730) { // 2 years
                $risks[] = [
                    'type' => 'stale',
                    'severity' => 'medium',
                    'message' => "Package not updated in " . round($daysSinceUpdate) . " days",
                ];
            }
        }

        // Check maintainer count
        $maintainers = $package['maintainers'] ?? [];
        if (count($maintainers) < 2) {
            $risks[] = [
                'type' => 'single_maintainer',
                'severity' => 'low',
                'message' => 'Single maintainer - bus factor risk',
            ];
        }

        return $risks;
    }

    private function determineSeverity(array $advisory): string
    {
        // Check CVSS score if available
        $cvss = $advisory['cvss']['score'] ?? null;
        if ($cvss !== null) {
            if ($cvss >= 9.0) return 'critical';
            if ($cvss >= 7.0) return 'high';
            if ($cvss >= 4.0) return 'medium';
            return 'low';
        }
        return 'unknown';
    }
}
